const HomeDemo = () => {
    const googleLogin = () => {
        window.location.href = 'http://localhost:8080/oauth/authorization/google'
    }
    return (
        <div>
            <h2>Welcome to the OAuth Demo</h2>
            <button onClick={googleLogin}>Login with Google</button>
        </div>
    )
}
export default HomeDemo;
